  v_ja_existem INT := 0;
  v_linkados INT := 0;
BEGIN
  -- Temp table com os dados crus
  CREATE TEMP TABLE _bat_imp (
    data_batismo DATE NOT NULL,
    nome TEXT NOT NULL,
    sobrenome TEXT NOT NULL,
    cpf TEXT,
    telefone TEXT,
    email TEXT,
    data_nascimento DATE,
    status TEXT NOT NULL,
    observacoes TEXT,
    membro_id UUID
  ) ON COMMIT DROP;

  INSERT INTO _bat_imp (data_batismo, nome, sobrenome, cpf, telefone, email, data_nascimento, status, observacoes)
  SELECT
    (r->>'d')::date,
    r->>'n',
    r->>'s',
    NULLIF(r->>'cpf', ''),
    NULLIF(r->>'t', ''),
    NULLIF(r->>'e', ''),
    NULLIF(r->>'dn', '')::date,
    r->>'st',
    NULLIF(r->>'o', '')
  FROM jsonb_array_elements(v_records) r;

  -- Linka com mem_membros existentes via CPF (quando disponivel e 11 digitos)
  UPDATE _bat_imp b
  SET membro_id = m.id
  FROM mem_membros m
  WHERE b.cpf IS NOT NULL
    AND length(b.cpf) = 11
    AND m.cpf = b.cpf;

  GET DIAGNOSTICS v_linkados = ROW_COUNT;

  -- Insere apenas o que ainda nao existe (compativel com seed do PR #377)
  INSERT INTO batismo_inscricoes (
    membro_id, nome, sobrenome, data_nascimento, cpf, telefone, email,
    status, data_batismo, origem, observacoes
  )
  SELECT
    b.membro_id, b.nome, b.sobrenome, b.data_nascimento, b.cpf, b.telefone, b.email,
    b.status, b.data_batismo, 'manual', b.observacoes
  FROM _bat_imp b
  WHERE NOT EXISTS (
    SELECT 1 FROM batismo_inscricoes bi
    WHERE lower(bi.nome) = lower(b.nome)
      AND lower(bi.sobrenome) = lower(b.sobrenome)
      AND bi.data_batismo = b.data_batismo
  );

  GET DIAGNOSTICS v_inseridos = ROW_COUNT;

  SELECT COUNT(*) - v_inseridos INTO v_ja_existem FROM _bat_imp;

  RAISE NOTICE 'batismo backfill: linkados=%, inseridos=%, ja_existem=%',
    v_linkados, v_inseridos, v_ja_existem;
END
$migration$;
